//! Distillation-dataset training: TinyStories (roneneldan/TinyStories, the
//! GPT-4-only "V2" split — synthetic short stories generated by a much larger
//! teacher model, restricted to a ~1,500-word children's-story vocabulary) with
//! a small BPE tokenizer trained specifically on that corpus, instead of
//! reusing a much larger generic tokenizer (e.g. `train_small.rs`'s GPT-2 BPE,
//! vocab 50257).
//!
//! Why a right-sized tokenizer matters here beyond tokenization quality: `vocab`
//! directly drives the tied LM head's memory-bandwidth cost (it sweeps the
//! full `[vocab, hidden]` embedding table every step — see RESEARCH_LOG.md
//! 2026-07-04/05, where this was found to be the dominant cost at production
//! scale). TinyStories' restricted lexicon needs nowhere near 50257 subwords,
//! so a small custom tokenizer (see `train_bpe_tokenizer`) both fits the
//! corpus better and shrinks that dominant cost for free.
//!
//! Same architecture shape as `train_small_lod.rs` (fast dev-loop iteration),
//! same CKPT_TAG/RESUME/CKPT_EVERY/TOTAL_STEPS env conventions established
//! across the other `train_*` binaries this session.
//!
//! `cargo run --release --bin train_tinystories` trains + checkpoints.
//! `cargo run --release --bin train_tinystories -- --eval` loads the
//! checkpoint and reports its held-out CE.

use std::path::PathBuf;

use fydel::kernels::optimizer::AdaFactor;
use fydel::model::config::ModelConfig;
use fydel::model::model::{Model, cross_entropy};
use fydel::train::data::{self, CorpusReader};
use fydel::train::optim::Optimizer;
use fydel::train::r#loop::{BatchSource, TrainConfig, train};
use fydel::train::schedule::WsdSchedule;

const TARGET_VOCAB: usize = 8192;
const CACHE_DIR: &str = "cache/tinystories";
const TRAIN_URL: &str =
    "https://huggingface.co/datasets/roneneldan/TinyStories/resolve/main/TinyStoriesV2-GPT4-train.txt";
/// Cap on downloaded/tokenized characters -- NOT the full 2.23GB train split.
/// Sized for a fast dev-loop first run; raise (or remove the cap) once the
/// pipeline is confirmed working end-to-end and a longer/bigger run is wanted.
const MAX_CHARS: usize = 20_000_000;

fn cache_dir() -> PathBuf {
    PathBuf::from(CACHE_DIR)
}

fn load_corpus() -> (usize, CorpusReader) {
    let max_chars: usize = std::env::var("MAX_CHARS").ok().and_then(|v| v.parse().ok()).unwrap_or(MAX_CHARS);
    let dir = cache_dir();
    std::fs::create_dir_all(&dir).expect("failed to create cache dir");

    // Encode max_chars into the cache filenames -- otherwise a smoke test with
    // a small MAX_CHARS would leave a too-small cached text/tokenizer that a
    // later, bigger run would silently (and wrongly) reuse.
    let text_path = dir.join(format!("TinyStoriesV2-GPT4-train.{max_chars}.txt"));
    if !text_path.exists() {
        eprintln!("downloading TinyStories train split (capped at {max_chars} chars)…");
        let resp = ureq::get(TRAIN_URL).call().expect("TinyStories download failed");
        let mut reader = resp.into_reader();
        // Bounded manual read loop (not `.take()`: ureq's reader isn't `Sized`,
        // and `read_to_end` would stream the whole 2.23GB file regardless of
        // MAX_CHARS) -- stop once we have enough bytes for MAX_CHARS chars
        // (4x headroom covers worst-case multi-byte UTF-8).
        let cap = max_chars * 4;
        let mut buf = Vec::with_capacity(cap.min(64_000_000));
        let mut chunk = [0u8; 65536];
        loop {
            if buf.len() >= cap {
                break;
            }
            let n = std::io::Read::read(&mut reader, &mut chunk).expect("failed reading TinyStories response");
            if n == 0 {
                break;
            }
            buf.extend_from_slice(&chunk[..n]);
        }
        std::fs::write(&text_path, &buf).expect("failed to cache TinyStories text");
    }
    let mut text = std::fs::read_to_string(&text_path).expect("failed to read cached TinyStories text");
    text.truncate(text.char_indices().nth(max_chars).map_or(text.len(), |(i, _)| i));

    let tok_path = dir.join(format!("tokenizer.{max_chars}.json"));
    let tok = data::train_bpe_tokenizer(&text, TARGET_VOCAB, &tok_path).expect("tokenizer training failed");
    let vocab = tok.get_vocab_size(true);
    eprintln!("tokenizer ready: {vocab} vocab (target was {TARGET_VOCAB})");

    let tokens = data::tokenize(&tok, &text).expect("tokenization failed");
    (vocab, CorpusReader::new(tokens))
}

fn small_cfg(vocab: usize) -> ModelConfig {
    let mut c = ModelConfig::default();
    c.n_layers = 12;
    c.full_attn_layers = 3; // 3/12 matches production's 24/96 ratio
    c.hidden = 256;
    c.n_q_heads = 4;
    c.n_kv_heads = 1;
    c.head_dim = 64;
    c.ffn_dim = 768;
    c.block = 64;
    c.n_active = 3;
    c.dict_k = 8;
    c.kv_block = 64;
    c.window = 64;
    c.vocab = vocab;
    c.max_seq = 512;
    c.validate();
    c
}

const EVAL_SEQ_LEN: usize = 256;
const EVAL_WINDOWS: usize = 200;

fn eval_loss<B: BatchSource>(model: &Model, src: &mut B, seq_len: usize, n_windows: usize) -> f32 {
    let vocab = model.config().vocab;
    let mut total = 0.0f32;
    let mut n = 0usize;
    let mut pool = fydel::kernels::scratch::BufPool::new();
    for _ in 0..n_windows {
        let Some((ids, targets)) = src.next_batch(seq_len) else { break };
        let fwd = model.forward(&ids, &mut pool);
        let (ce, _) = cross_entropy(&fwd.logits, vocab, &targets);
        total += ce;
        n += 1;
    }
    total / n.max(1) as f32
}

fn main() {
    let args: Vec<String> = std::env::args().collect();
    let ckpt_tag = std::env::var("CKPT_TAG").unwrap_or_default();
    let ckpt_path = if !ckpt_tag.is_empty() {
        PathBuf::from(format!("checkpoints/fydel_tinystories_{ckpt_tag}.ckpt"))
    } else {
        PathBuf::from("checkpoints/fydel_tinystories.ckpt")
    };
    if let Some(p) = ckpt_path.parent() {
        let _ = std::fs::create_dir_all(p);
    }

    if args.iter().any(|a| a == "--eval") {
        let (model, _opt) =
            fydel::train::checkpoint::load(&ckpt_path).expect("no checkpoint found — run training first");
        eprintln!("checkpoint loaded: vocab={} n_layers={}", model.config().vocab, model.config().n_layers);

        let (_vocab, reader) = load_corpus();
        let (_train_r, mut val_r) = reader.split_val(0.1);
        eprintln!("held-out set: {} tokens", val_r.len());
        let loss = eval_loss(&model, &mut val_r, EVAL_SEQ_LEN, EVAL_WINDOWS);
        eprintln!("held-out CE: {loss:.4} nats");
        return;
    }

    let (vocab, reader) = load_corpus();
    eprintln!("corpus ready: {} tokens, vocab {}", reader.len(), vocab);
    let (mut train_r, val_r) = reader.split_val(0.1);
    eprintln!("train/val split: {} / {} tokens", train_r.len(), val_r.len());

    let resume_env = std::env::var("RESUME").ok();
    let resume = if ckpt_tag.is_empty() {
        resume_env.as_deref() != Some("0")
    } else {
        resume_env.as_deref() == Some("1")
    };
    let (mut model, mut opt, start_step) = if resume && ckpt_path.exists() {
        let (m, opt_state) = fydel::train::checkpoint::load(&ckpt_path)
            .expect("failed to load checkpoint for resume (set RESUME=0 to start fresh instead)");
        let step = fydel::train::checkpoint::load_step(&ckpt_path).unwrap_or(0);
        eprintln!("resuming from {} at step {step} (set RESUME=0 to start fresh)", ckpt_path.display());
        (m, Optimizer::from_parts(AdaFactor::default(), opt_state), step)
    } else {
        let m = Model::new(small_cfg(vocab), 0xF1DE1_5EED);
        let opt = Optimizer::with_config(&m, AdaFactor::default());
        (m, opt, 0)
    };

    let total_steps: usize = std::env::var("TOTAL_STEPS").ok().and_then(|v| v.parse().ok()).unwrap_or(3000);
    let train_cfg = TrainConfig {
        total_steps,
        micro_batches: 4,
        seq_len_init: 128,
        seq_len_final: 256,
        curriculum_switch: 1500,
        schedule: WsdSchedule::new(3e-3, 3e-4, 200, total_steps / 5, total_steps),
        probe_weight: 0.1,
        probe_anneal_steps: 500,
    };

    eprintln!("training TinyStories model ({} layers, vocab {vocab}) from step {start_step} to {total_steps} …",
        model.config().n_layers);
    let ckpt_every: usize = std::env::var("CKPT_EVERY").ok().and_then(|v| v.parse().ok()).unwrap_or(500);
    let hist = train(&mut model, &mut opt, &mut train_r, &train_cfg, Some((ckpt_every, &ckpt_path)), 5, start_step);

    if let Some(last) = hist.last() {
        eprintln!("done: final ce {:.4} at step {}", last.ce, last.step);
    }
    fydel::train::checkpoint::save(&model, opt.state(), &ckpt_path)
        .expect("final checkpoint save failed");
    fydel::train::checkpoint::save_step(&ckpt_path, hist.last().map_or(start_step, |m| m.step + 1))
        .expect("final step-sidecar save failed");
    eprintln!("checkpoint written to {}", ckpt_path.display());
}
